{% if daily_change_pct is not none %}
  {% if daily_change_pct >= 0 %}
    +{{ "%.2f"|format(daily_change_pct) }}%
  {% else %}
    {{ "%.2f"|format(daily_change_pct) }}%
  {% endif %}
