{% set total_val = type_percents.values()|sum %}

{% set dashoffset = 0 %}
{% for type_name, pct in type_percents.items() %}
  {% set color = {'Акции':'#2196F3', 'Облигации':'#FF9800', 'Фонды':'#4CAF50'}.get(type_name, '#9E9E9E') %}
  {% set circumference = 2 * 3.1415926535 * 70 %}
  {% set dasharray = (circumference * pct / 100)|round(2) %}

  {% set dashoffset = dashoffset - dasharray %}
{% endfor %}


Структура активов
{% set y_legend = 300 %}
{% for type_name, pct in type_percents.items() %}
  {% set color = {'Акции':'#2196F3', 'Облигации':'#FF9800', 'Фонды':'#4CAF50'}.get(type_name, '#9E9E9E') %}

  {{ type_name }}: {{ "%.1f"|format(pct) }}%
  {% set y_legend = y_legend + 20 %}
{% endfor %}


ТОП-5 ПОЗИЦИЙ
{% set bar_max = top5[0].value if top5 else 1 %}
{% set y = 230 %}
{% for pos in top5 %}
  {% set bar_width = (pos.value / bar_max) * 300 %}
  {% set color = '#4caf50' if pos.yield_pct >= 0 else '#f44336' %}

  {{ pos.display_name }}
  {{ pos.value_formatted }} ₽

    {{ "%.1f"|format(pos.yield_pct) }}%

  {% set y = y + 28 %}
{% endfor %}



